/* demo_lpr_images.S — Embed demo_lpr_test_images.bin into .lpr_images DDR section.
 *
 * linker_lpr.ld maps this section to DDR at 0x00900000.
 * demo_lpr.c accesses images via:
 *   const int32_t *img = lpr_images_start + (uint32_t)i * LPR_TEST_IMG_PIXELS;
 *
 * Binary layout: N_images × 784 int32_t values (little-endian), sequential.
 * Generated by: python3 07_sw/lprnet_eval/gen_test_images.py
 */
    .section .lpr_images, "a"
    .global lpr_images_start
    .global lpr_images_end

lpr_images_start:
    .incbin "demo_lpr_test_images.bin"
lpr_images_end:
